"use client";

import type { Testimonial } from "@/lib/types";
import { TestimonialsPreview } from "./testimonials-preview";
import { useTestimonials } from "@/lib/queries/useTestimonials";

export function TestimonialsPreviewLoader() {
  const { data, isLoading } = useTestimonials({ featured: true });

  if (isLoading) return null;

  const items: Testimonial[] =
    (data || []).map((t) => ({
      id: t.id,
      name: t.name,
      rating: t.rating,
      content: t.content,
      visitDate: t.visitDate || "",
      isApproved: true,
    })) || [];

  return <TestimonialsPreview testimonials={items} />;
}
